// // This module implements a convolutional encoder with a constraint length of 3 and a rate of 1/2. It has 2 outputs for every single input bit. The encoding process is defined by the following connections:
// - Input bit (D) is connected to the first output (Y1) through an XOR with the output of the previous stage's memory (M1).
// - Input bit (D) is connected to the second output (Y2) through an XOR with the previous stages' memory (M1 and M2).
// The memory registers (M1 and M2) should shift with each new input bit.
module convolutional_encoder (
    input clk,
    input rst,
    input D,
    output reg Y1,
    output reg Y2
);
    reg M1, M2;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            M1 <= 0;
            M2 <= 0;
            Y1 <= 0;
            Y2 <= 0;
        end else begin
            Y1 <= D ^ M1; // First output
            Y2 <= D ^ M1 ^ M2; // Second output
            M2 <= M1; // Shift the memories
            M1 <= D; // New input to memory M1
        end
    end
endmodule

